const express = require("express");
const { OpenAI } = require("openai");

const app = express();
const client = new OpenAI();

app.get("/stream", async (req, res) => {
  const prompt = req.query.prompt || "Tell me a short story.";

  res.setHeader("Content-Type", "text/event-stream");
  res.setHeader("Cache-Control", "no-cache");
  res.setHeader("Connection", "keep-alive");
  res.setHeader("X-Accel-Buffering", "no");
  res.flushHeaders();

  try {
    const stream = client.chat.completions.stream({
      model: "gpt-4o",
      messages: [{ role: "user", content: prompt }],
    });

    let id = 0;
    for await (const chunk of stream) {
      const token = chunk.choices[0]?.delta?.content || "";
      if (token) {
        res.write(`id: ${id++}\ndata: ${JSON.stringify({ token })}\n\n`);
      }
    }
    res.write("data: [DONE]\n\n");
  } catch (err) {
    res.write(`event: error\ndata: ${JSON.stringify({ error: err.message })}\n\n`);
  } finally {
    res.end();
  }
});

app.listen(3000);

const es = new EventSource("/stream?prompt=Tell+me+a+story");
let buffer = "";

es.onopen = () => console.log("Connection opened");

es.onmessage = (event) => {
  if (event.data === "[DONE]") {
    es.close();
    console.log("Stream complete:", buffer);
    return;
  }
  const parsed = JSON.parse(event.data);
  buffer += parsed.token;
  document.getElementById("output").textContent = buffer;
};

// Named event type
es.addEventListener("progress", (event) => {
  const data = JSON.parse(event.data);
  console.log(`Progress: ${data.percent}%`);
});

es.onerror = (event) => {
  if (es.readyState === EventSource.CLOSED) {
    console.log("Connection closed");
  } else {
    console.warn("Connection error — will retry automatically");
  }
};

import json
import requests

def stream_openai(prompt: str, model: str = "gpt-4o"):
    """Stream OpenAI Chat Completions via SSE using the requests library."""
    headers = {
        "Authorization": f"Bearer {import_api_key()}",
        "Content-Type": "application/json",
        "Accept": "text/event-stream",
    }
    payload = {
        "model": model,
        "messages": [{"role": "user", "content": prompt}],
        "stream": True,
    }
    with requests.post(
        "https://api.openai.com/v1/chat/completions",
        headers=headers, json=payload, stream=True
    ) as resp:
        for line in resp.iter_lines(decode_unicode=True):
            if not line or line.startswith(":"):
                continue
            if line.startswith("data: "):
                data = line[6:]
                if data == "[DONE]":
                    return
                chunk = json.loads(data)
                token = chunk["choices"][0]["delta"].get("content", "")
                print(token, end="", flush=True)

def import_api_key():
    import os
    return os.environ["OPENAI_API_KEY"]

stream_openai("Explain quantum entanglement in simple terms.")

